package com.cho2hand.marketplace.controller.trust;import com.cho2hand.marketplace.dto.trust.*;import com.cho2hand.marketplace.service.trust.TransactionService;import jakarta.validation.Valid;import jakarta.validation.constraints.Positive;import org.springframework.http.HttpStatus;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1")public class TransactionController{private final TransactionService service;public TransactionController(TransactionService s){service=s;}@PostMapping("/listings/{listingId}/transactions")@ResponseStatus(HttpStatus.CREATED)public TransactionResponse confirm(@AuthenticationPrincipal Long user,@PathVariable @Positive Long listingId,@Valid @RequestBody ConfirmTransactionRequest request){return service.confirm(user,listingId,request);}@PostMapping("/transactions/{id}/confirm")public TransactionResponse confirmReceipt(@AuthenticationPrincipal Long user,@PathVariable @Positive Long id){return service.confirmReceipt(user,id);}@GetMapping("/transactions/mine")public java.util.List<TransactionResponse> mine(@AuthenticationPrincipal Long user){return service.mine(user);}@PostMapping("/transactions/{id}/reviews")@ResponseStatus(HttpStatus.CREATED)public void review(@AuthenticationPrincipal Long user,@PathVariable @Positive Long id,@Valid @RequestBody CreateReviewRequest request){service.review(user,id,request);}}
